                @QuickMenu.performed -= instance.OnQuickMenu;
                @QuickMenu.canceled -= instance.OnQuickMenu;
                @QuickSave.started -= instance.OnQuickSave;
                @QuickSave.performed -= instance.OnQuickSave;
                @QuickSave.canceled -= instance.OnQuickSave;
                @QuickLoad.started -= instance.OnQuickLoad;
                @QuickLoad.performed -= instance.OnQuickLoad;
                @QuickLoad.canceled -= instance.OnQuickLoad;
                @Menu.started -= instance.OnMenu;
                @Menu.performed -= instance.OnMenu;
                @Menu.canceled -= instance.OnMenu;
                @HUDToggle.started -= instance.OnHUDToggle;
                @HUDToggle.performed -= instance.OnHUDToggle;
                @HUDToggle.canceled -= instance.OnHUDToggle;
            }

            /// <summary>
            /// Unregisters <param cref="instance" /> and unregisters all input action callbacks via <see cref="MiscellaneousActions.UnregisterCallbacks(IMiscellaneousActions)" />.
            /// </summary>
            /// <seealso cref="MiscellaneousActions.UnregisterCallbacks(IMiscellaneousActions)" />
            public void RemoveCallbacks(IMiscellaneousActions instance)
