            /// <summary>
            /// Replaces all existing callback instances and previously registered input action callbacks associated with them with callbacks provided via <param cref="instance" />.
            /// </summary>
            /// <remarks>
            /// If <paramref name="instance" /> is <c>null</c>, calling this method will only unregister all existing callbacks but not register any new callbacks.
            /// </remarks>
            /// <seealso cref="MiscellaneousActions.AddCallbacks(IMiscellaneousActions)" />
            /// <seealso cref="MiscellaneousActions.RemoveCallbacks(IMiscellaneousActions)" />
            /// <seealso cref="MiscellaneousActions.UnregisterCallbacks(IMiscellaneousActions)" />
            public void SetCallbacks(IMiscellaneousActions instance)
            {
                foreach (var item in m_Wrapper.m_MiscellaneousActionsCallbackInterfaces)
